const fs = require\('fs'\);
const raw = fs.readFileSync\('C:/Users/Epic Gamer/.claude/projects/C--GIT-House-of-More/6bcef092-7cd6-483f-98f0-5c70c07a10a8/tool-results/mcp-claude_ai_Webflow-element_tool-1773255039849.txt', 'utf8'\);
const arr = JSON.parse\(raw\);
const text = arr[0].text;
const parsed = JSON.parse\(text\);

// Find elements with the target classes
const targets = ['embed-initial-fetch', 'embed-rsvp-event', 'embed-back-button', 'embed-check-origin'];
function search\(elements\) {
  let found = [];
  for \(const el of elements\) {
    const classes = \(el.classes || []\).join\(' '\);
    if \(targets.some\(t => classes.includes\(t\)\)\) {
      found.push\({id: el.id, type: el.type, classes: el.classes, customCode: el.customCode, innerHTML: el.innerHTML}\);
    }
    if \(el.children\) found = found.concat\(search\(el.children\)\);
  }
  return found;
}
const results = search\(Array.isArray\(parsed\) ? parsed : [parsed]\);
console.log\(JSON.stringify\(results, null, 2\)\);
")

